import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const D=JSON.parse('{"title":"DDA授权失败怎么办","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/dda-failure.md","filePath":"zh-CN/troubleshooting/dda-failure.md"}'),o={name:"troubleshooting/dda-failure.md"};function i(l,t,n,h,s,p){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="dda授权失败怎么办" tabindex="-1">DDA授权失败怎么办 <a class="header-anchor" href="#dda授权失败怎么办" aria-label="Permalink to &quot;DDA授权失败怎么办&quot;">​</a></h1><p>DDA 分为两种不同服务，处理方式不同：</p><ul><li><strong>eDDA</strong>（香港）：基于 FPS 转数快系统，用于港元入金</li><li><strong>DDA</strong>（新加坡）：直接扣款授权服务，用于新加坡元入金</li></ul><h2 id="edda-授权失败-香港" tabindex="-1">eDDA 授权失败（香港） <a class="header-anchor" href="#edda-授权失败-香港" aria-label="Permalink to &quot;eDDA 授权失败（香港）&quot;">​</a></h2><p>授权时提示错误，根据错误信息处理：</p><table tabindex="0"><thead><tr><th>错误信息</th><th>原因</th><th>处理方式</th></tr></thead><tbody><tr><td>Debtor account name / ID not matched</td><td>姓名或证件格式不符</td><td>确认填写大写英文姓名，证件类型与银行开户时一致</td></tr><tr><td>Invalid debtor account number</td><td>账号有误或使用了分币种账号</td><td>填写综合账号主账号，去掉银行代码前缀；部分银行港币账号末尾为 1 或 2</td></tr><tr><td>Mandate identification already exists</td><td>同时在银行端和 App 端发起了授权</td><td>等待其中一个完成或失效后，仅在 App 端重新发起</td></tr><tr><td>Debtor account not found</td><td>账号错误</td><td>核对银行账号，确认没有多余空格或错位</td></tr><tr><td>Rejected by Other bank</td><td>账户类型问题</td><td>确认绑定的是港元账户，而非美元账户</td></tr><tr><td>Invalid Payer ID</td><td>证件信息不一致</td><td>确认长桥账户证件信息与银行端一致</td></tr></tbody></table><p><strong>华侨银行</strong>：授权一般需 2 个工作日处理。若长时间无结果，检查是否选错了银行代码，可删除后重新发起。</p><p><strong>重置授权</strong>：如排查后仍无法授权，联系银行端重置 eDDA，再在 App 内重新发起。</p><h2 id="dda-授权失败-新加坡" tabindex="-1">DDA 授权失败（新加坡） <a class="header-anchor" href="#dda-授权失败-新加坡" aria-label="Permalink to &quot;DDA 授权失败（新加坡）&quot;">​</a></h2><p>根据错误码处理：</p><table tabindex="0"><thead><tr><th>错误码 / 提示</th><th>原因</th><th>处理方式</th></tr></thead><tbody><tr><td>1209（Refer to your payer/payee）</td><td>银行账户余额或额度不足</td><td>确保银行账户余额充足后重新授权</td></tr><tr><td>1100（Other reason）</td><td>曾在银行端删除过 DDA 绑定</td><td>联系长桥客服关闭旧记录，再重新授权</td></tr><tr><td>ID number verification failed</td><td>长桥注册的身份证号与银行端不一致</td><td>确认填写的证件号与银行开户证件一致</td></tr><tr><td>BA3002（Consent not given）</td><td>未完整阅读条款就点击了取消</td><td>重新发起授权流程，完整阅读条款后提交</td></tr></tbody></table><h2 id="授权成功但无法发起入金" tabindex="-1">授权成功但无法发起入金 <a class="header-anchor" href="#授权成功但无法发起入金" aria-label="Permalink to &quot;授权成功但无法发起入金&quot;">​</a></h2><p>授权状态正常但点击 DDA/eDDA 入金时报错：</p><ol><li>检查银行账户余额是否充足（账户余额不足时部分银行会拒绝扣款）</li><li>确认银行卡未被冻结或限制</li><li>检查长桥 App 内显示的授权状态是否为「已授权」</li></ol><h2 id="仍无法解决" tabindex="-1">仍无法解决 <a class="header-anchor" href="#仍无法解决" aria-label="Permalink to &quot;仍无法解决&quot;">​</a></h2><p>联系客服时提供：</p><ul><li>错误截图（含完整错误信息）</li><li>使用的银行名称</li><li>授权失败的时间</li></ul><p><strong>在线客服</strong>：长桥 App → 我的 → 帮助与客服 → 在线客服</p>',18)])])}const c=d(o,[["render",i]]);export{D as __pageData,c as default};
